import Cell from '../../cell/Cell.js';
/**
 * An abstraction of an internal hierarchy node or edge.
 *
 * @category Layout
 */
class GraphAbstractHierarchyCell extends Cell {
    constructor() {
        super();
        this.swimlaneIndex = null;
        /**
         * The maximum rank this cell occupies. Default is -1.
         */
        this.maxRank = -1;
        /**
         * The minimum rank this cell occupies. Default is -1.
         */
        this.minRank = -1;
        /**
         * The width of this cell. Default is 0.
         */
        this.width = 0;
        /**
         * The height of this cell. Default is 0.
         */
        this.height = 0;
        /**
         * A cached version of the cells this cell connects to on the next layer up
         */
        this.nextLayerConnectedCells = null;
        /**
         * A cached version of the cells this cell connects to on the next layer down
         */
        this.previousLayerConnectedCells = null;
        this.x = [];
        this.y = [];
        this.temp = [];
    }
    /**
     * Returns whether or not this cell is an edge
     */
    isEdge() {
        return false;
    }
    /**
     * Returns whether or not this cell is a node
     */
    isVertex() {
        return false;
    }
    /**
     * Set the value of x for the specified layer
     */
    setX(layer, value) {
        if (this.isVertex()) {
            this.x[0] = value;
        }
        else if (this.isEdge()) {
            this.x[layer - this.minRank - 1] = value;
        }
    }
    /**
     * Gets the value of x on the specified layer
     */
    getX(layer) {
        if (this.isVertex()) {
            return this.x[0];
        }
        if (this.isEdge()) {
            return this.x[layer - this.minRank - 1];
        }
        return 0.0;
    }
    /**
     * Set the value of y for the specified layer
     */
    setY(layer, value) {
        if (this.isVertex()) {
            this.y[0] = value;
        }
        else if (this.isEdge()) {
            this.y[layer - this.minRank - 1] = value;
        }
    }
}
export default GraphAbstractHierarchyCell;
